using Microsoft.VisualStudio.TestTools.UnitTesting;
using Payments;

namespace Payments.Tests;

[TestClass]
public sealed class PaymentGatewayTests
{
    private readonly PaymentGateway _sut = new();

    #region ChargeAsync Tests

    [TestMethod]
    [DataRow("tok_valid_visa", 100.00, DisplayName = "Standard charge amount")]
    [DataRow("tok_valid_mc", 0.50, DisplayName = "Minimum valid amount")]
    [DataRow("tok_valid_amex", 9999.99, DisplayName = "Large charge amount")]
    public async Task ChargeAsync_ValidTokenAndAmount_ThrowsNotImplementedException(string cardToken, double amount)
    {
        // Act & Assert — methods are not yet implemented
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync(cardToken, (decimal)amount));
    }

    [TestMethod]
    [DataRow(null, DisplayName = "Null card token")]
    [DataRow("", DisplayName = "Empty card token")]
    [DataRow("   ", DisplayName = "Whitespace card token")]
    public async Task ChargeAsync_InvalidToken_ThrowsNotImplementedException(string? cardToken)
    {
        // Arrange
        decimal amount = 50.00m;

        // Act & Assert — once implemented, should throw ArgumentException
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync(cardToken!, amount));
    }

    [TestMethod]
    [DataRow(0.0, DisplayName = "Zero amount")]
    [DataRow(-10.0, DisplayName = "Negative amount")]
    public async Task ChargeAsync_InvalidAmount_ThrowsNotImplementedException(double amount)
    {
        // Arrange
        string cardToken = "tok_valid";

        // Act & Assert — once implemented, should throw ArgumentException for invalid amounts
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync(cardToken, (decimal)amount));
    }

    #endregion

    #region RefundAsync Tests

    [TestMethod]
    [DataRow("ch_abc123", DisplayName = "Standard charge ID")]
    [DataRow("ch_longid_xyz789_test", DisplayName = "Long charge ID")]
    public async Task RefundAsync_ValidChargeId_ThrowsNotImplementedException(string chargeId)
    {
        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.RefundAsync(chargeId));
    }

    [TestMethod]
    [DataRow(null, DisplayName = "Null charge ID")]
    [DataRow("", DisplayName = "Empty charge ID")]
    [DataRow("   ", DisplayName = "Whitespace charge ID")]
    public async Task RefundAsync_InvalidChargeId_ThrowsNotImplementedException(string? chargeId)
    {
        // Act & Assert — once implemented, should throw ArgumentException
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.RefundAsync(chargeId!));
    }

    #endregion

    #region Record Model Tests

    [TestMethod]
    public void ChargeResult_Properties_SetCorrectly()
    {
        // Arrange & Act
        var result = new ChargeResult("ch_123", true);

        // Assert
        Assert.AreEqual("ch_123", result.ChargeId);
        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public void ChargeResult_FailedCharge_ReportsFailure()
    {
        // Arrange & Act
        var result = new ChargeResult("ch_456", false);

        // Assert
        Assert.AreEqual("ch_456", result.ChargeId);
        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public void RefundResult_Properties_SetCorrectly()
    {
        // Arrange & Act
        var result = new RefundResult("rf_789", true);

        // Assert
        Assert.AreEqual("rf_789", result.RefundId);
        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public void RefundResult_FailedRefund_ReportsFailure()
    {
        // Arrange & Act
        var result = new RefundResult("rf_000", false);

        // Assert
        Assert.AreEqual("rf_000", result.RefundId);
        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public void ChargeResult_Equality_WorksByValue()
    {
        // Records should support value equality
        var a = new ChargeResult("ch_1", true);
        var b = new ChargeResult("ch_1", true);
        var c = new ChargeResult("ch_2", true);

        Assert.AreEqual(a, b);
        Assert.AreNotEqual(a, c);
    }

    [TestMethod]
    public void RefundResult_Equality_WorksByValue()
    {
        var a = new RefundResult("rf_1", true);
        var b = new RefundResult("rf_1", true);
        var c = new RefundResult("rf_1", false);

        Assert.AreEqual(a, b);
        Assert.AreNotEqual(a, c);
    }

    #endregion
}

